config.script:
if self.view.params.configMode:
	system.perspective.print(self.session.custom.buttonConfigDock.isOpen)
	if self.session.custom.buttonConfigDock.isOpen != True:
		parameters = {'buttonIndex': event.params.buttonIndex}
		system.perspective.sendMessage('isEditing', payload = parameters)
		self.session.custom.buttonConfigDock.headOperationUUID = self.view.params.operation
		self.session.custom.buttonConfigDock.isOpen = bool(True)
		self.session.custom.buttonConfigDock.buttonIndex = event.params.buttonIndex
		system.perspective.openDock('ButtonConfig')

transforms.code:
try:
	if value.primaryView.height > 0:
		transform = 'scale(%s)' % min(1.0*value.primaryView.height/value.height, 1.0*value.primaryView.width/value.width)
	else:
		transform = 'scale(%s)' % min(1.0*value.defaultSize.height/value.height, 1.0*value.defaultSize.width/value.width)
except:
	transform = 'scale(1)'

return transform

messageHandlers.script:
axis = payload['axis']
amount = payload['amount']
index = payload['index']
for w in self.view.custom.widgets:
	if w['viewParams']['buttonIndex'] == index:
		w[axis] += amount

index = payload['index']
amount = payload['amount']
for w in self.view.custom.widgets:
	if w['viewParams']['buttonIndex'] == index:
		w['hFrac'] += amount
		w['wFrac'] += amount
